BEGIN;

CREATE EXTENSION IF NOT EXISTS postgis;
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

CREATE SCHEMA IF NOT EXISTS dominio;
CREATE SCHEMA IF NOT EXISTS dgeo;
CREATE SCHEMA IF NOT EXISTS macrocontrole;

-- ============================================================================
-- Tabelas (espelho do schema SAP — sem FKs para isolar o seed)
-- ============================================================================

CREATE TABLE IF NOT EXISTS dominio.status (
    code smallint PRIMARY KEY, nome character varying(255) NOT NULL
);
CREATE TABLE IF NOT EXISTS dominio.tipo_situacao (
    code smallint PRIMARY KEY, nome character varying(255)
);
CREATE TABLE IF NOT EXISTS dominio.tipo_etapa (
    code smallint PRIMARY KEY, nome character varying(255) NOT NULL
);
CREATE TABLE IF NOT EXISTS dominio.tipo_fase (
    code smallint PRIMARY KEY, nome character varying(255) NOT NULL,
    cor character varying(255) NOT NULL
);
CREATE TABLE IF NOT EXISTS dgeo.usuario (
    id integer PRIMARY KEY, login character varying(255) NOT NULL,
    nome character varying(255) NOT NULL, nome_guerra character varying(255) NOT NULL,
    tipo_turno_id smallint NOT NULL, tipo_posto_grad_id smallint NOT NULL,
    administrador boolean DEFAULT false NOT NULL, ativo boolean DEFAULT true NOT NULL,
    uuid uuid NOT NULL
);
CREATE TABLE IF NOT EXISTS macrocontrole.linha_producao (
    id integer PRIMARY KEY, nome character varying(255) NOT NULL,
    nome_abrev character varying(255) NOT NULL, tipo_produto_id smallint NOT NULL,
    descricao text, disponivel boolean DEFAULT true NOT NULL
);
CREATE TABLE IF NOT EXISTS macrocontrole.fase (
    id integer PRIMARY KEY, tipo_fase_id smallint NOT NULL,
    linha_producao_id integer NOT NULL, ordem integer NOT NULL
);
CREATE TABLE IF NOT EXISTS macrocontrole.subfase (
    id integer PRIMARY KEY, nome character varying(255) NOT NULL,
    fase_id integer NOT NULL, ordem integer NOT NULL
);
CREATE TABLE IF NOT EXISTS macrocontrole.projeto (
    id integer PRIMARY KEY, nome character varying(255) NOT NULL,
    nome_abrev character varying(255) NOT NULL, descricao text,
    status_id smallint NOT NULL
);
CREATE TABLE IF NOT EXISTS macrocontrole.lote (
    id integer PRIMARY KEY, nome character varying(255) NOT NULL,
    nome_abrev character varying(255) NOT NULL, denominador_escala integer NOT NULL,
    linha_producao_id integer NOT NULL, projeto_id integer NOT NULL,
    descricao text, status_id smallint NOT NULL
);
CREATE TABLE IF NOT EXISTS macrocontrole.bloco (
    id integer PRIMARY KEY, nome character varying(255) NOT NULL,
    prioridade integer NOT NULL, status_id smallint NOT NULL, lote_id integer NOT NULL
);
CREATE TABLE IF NOT EXISTS macrocontrole.etapa (
    id integer PRIMARY KEY, tipo_etapa_id smallint NOT NULL,
    subfase_id integer NOT NULL, lote_id integer NOT NULL, ordem integer NOT NULL
);
CREATE TABLE IF NOT EXISTS macrocontrole.unidade_trabalho (
    id integer PRIMARY KEY, nome character varying(255),
    epsg character varying(5) NOT NULL, dado_producao_id integer NOT NULL,
    subfase_id integer NOT NULL, lote_id integer NOT NULL, bloco_id integer NOT NULL,
    disponivel boolean DEFAULT false NOT NULL, dificuldade integer DEFAULT 0 NOT NULL,
    tempo_estimado_minutos integer DEFAULT 0 NOT NULL, prioridade integer NOT NULL,
    observacao text, geom public.geometry(Polygon,4326) NOT NULL
);
CREATE TABLE IF NOT EXISTS macrocontrole.atividade (
    id integer PRIMARY KEY, etapa_id integer NOT NULL,
    unidade_trabalho_id integer NOT NULL, usuario_id integer,
    tipo_situacao_id smallint NOT NULL,
    data_inicio timestamp with time zone, data_fim timestamp with time zone,
    observacao text
);
CREATE TABLE IF NOT EXISTS macrocontrole.perfil_producao (
    id integer PRIMARY KEY, nome character varying(255) NOT NULL
);
CREATE TABLE IF NOT EXISTS macrocontrole.perfil_producao_etapa (
    id integer PRIMARY KEY, perfil_producao_id integer NOT NULL,
    subfase_id integer NOT NULL, tipo_etapa_id smallint NOT NULL, prioridade integer NOT NULL
);
CREATE TABLE IF NOT EXISTS macrocontrole.perfil_producao_operador (
    id integer PRIMARY KEY, usuario_id integer NOT NULL, perfil_producao_id integer NOT NULL
);

-- ============================================================================
-- Limpeza (CASCADE resolve dependências)
-- ============================================================================
TRUNCATE TABLE
    macrocontrole.atividade,
    macrocontrole.perfil_producao_operador,
    macrocontrole.perfil_producao_etapa,
    macrocontrole.perfil_producao,
    macrocontrole.unidade_trabalho,
    macrocontrole.etapa,
    macrocontrole.bloco,
    macrocontrole.lote,
    macrocontrole.projeto,
    macrocontrole.subfase,
    macrocontrole.fase,
    macrocontrole.linha_producao,
    dgeo.usuario,
    dominio.tipo_fase,
    dominio.tipo_etapa,
    dominio.tipo_situacao,
    dominio.status
CASCADE;

-- ============================================================================
-- Dados reais extraídos do dump SAP
-- ============================================================================
-- dominio.status

-- dominio.tipo_situacao

-- dominio.tipo_etapa

-- dominio.tipo_fase

-- dgeo.usuario

-- macrocontrole.linha_producao

-- macrocontrole.fase

-- macrocontrole.subfase

-- macrocontrole.projeto

-- macrocontrole.lote

-- macrocontrole.bloco

-- macrocontrole.etapa

-- macrocontrole.unidade_trabalho

-- macrocontrole.atividade

-- macrocontrole.perfil_producao

-- macrocontrole.perfil_producao_etapa

-- macrocontrole.perfil_producao_operador


COMMIT;